// Sadə Java proqramı
public class HelloWorld {
  public static void main(String[] args) {
    System.out.println("Hello, World!");
  }
}
// Çıxış: Hello, World!

// 1. Dəyişənlər və Tiplər
public class VariablesExample {
  public static void main(String[] args) {
    int age = 25; // Tam ədəd
    double price = 99.99; // Onluq ədəd
    String name = "Alice"; // Sətir
    boolean isStudent = true; // Boolean
    System.out.println("Name: " + name + ", Age: " + age + ", Price: " + price + ", Student: " + isStudent);
  }
}
// Çıxış: Name: Alice, Age: 25, Price: 99.99, Student: true

// 2. Şərtlər (if-else)
public class ConditionsExample {
  public static void main(String[] args) {
    int age = 18;
    if (age >= 18) {
      System.out.println("You are an adult.");
    } else {
      System.out.println("You are a minor.");
    }
  }
}
// Çıxış: You are an adult.

// 3. Dövrlər (for, while)
public class LoopsExample {
  public static void main(String[] args) {
    // For dövrü
    for (int i = 1; i <= 5; i++) {
      System.out.println("Count: " + i);
    }
    // While dövrü
    int count = 1;
    while (count <= 3) {
      System.out.println("While count: " + count);
      count++;
    }
  }
}
// Çıxış: Count: 1
// Count: 2
// Count: 3
// Count: 4
// Count: 5
// While count: 1
// While count: 2
// While count: 3

// 4. Metodlar
public class MethodsExample {
  public static String greet(String name) {
    return "Hello, " + name;
  }
  public static void main(String[] args) {
    String message = greet("Bob");
    System.out.println(message);
  }
}
// Çıxış: Hello, Bob

// 5. Siniflər və Obyektlər
public class User {
  String name;
  int age;

  public User(String name, int age) {
    this.name = name;
    this.age = age;
  }

  public String getInfo() {
    return "Name: " + name + ", Age: " + age;
  }

  public static void main(String[] args) {
    User user = new User("Alice", 25);
    System.out.println(user.getInfo());
  }
}
// Çıxış: Name: Alice, Age: 25

public class Product {
  String id;
  String name;
  double price;

  public Product(String id, String name, double price) {
    this.id = id;
    this.name = name;
    this.price = price;
  }

  public String getInfo() {
    return "Product: " + name + ", ID: " + id + ", Price: " + price;
  }
}

public class Store {
  public static void main(String[] args) {
    Product product1 = new Product("P001", "Laptop", 999.99);
    Product product2 = new Product("P002", "Phone", 499.99);
    System.out.println(product1.getInfo());
    System.out.println(product2.getInfo());
  }
}
// Çıxış: Product: Laptop, ID: P001, Price: 999.99
// Product: Phone, ID: P002, Price: 499.99

